 60‚Üí   * These files have special installation patterns that don't fit the config-driven model
 61‚Üí   * Note: codex was migrated to config-driven (platform-codes.yaml) and no longer needs a custom installer
 62‚Üí   */
 63‚Üí  async loadCustomInstallerFiles() {
 64‚Üí    const ideDir = __dirname;
 65‚Üí    const customFiles = ['github-copilot.js', 'kilo.js', 'rovodev.js'];
 66‚Üí
 67‚Üí    for (const file of customFiles) {
 68‚Üí      const filePath = path.join(ideDir, file);
 69‚Üí      if (!fs.existsSync(filePath)) continue;
 70‚Üí
 71‚Üí      try {
 72‚Üí        const HandlerModule = require(filePath);
 73‚Üí        const HandlerClass = HandlerModule.default || Object.values(HandlerModule)[0];
 74‚Üí
 75‚Üí        if (HandlerClass) {
 76‚Üí          const instance = new HandlerClass();
 77‚Üí          if (instance.name && typeof instance.name === 'string') {
 78‚Üí            if (typeof instance.setBmadFolderName === 'function') {
 79‚Üí              instance.setBmadFolderName(this.bmadFolderName);
 80‚Üí            }
 81‚Üí            this.handlers.set(instance.name, instance);
 82‚Üí          }
 83‚Üí        }
 84‚Üí      } catch (error) {
 85‚Üí        await prompts.log.warn(`Warning: Could not load ${file}: ${error.message}`);
 86‚Üí      }
