103‚Üí
104‚Üí      // Skip if no installer config (platform may not need installation)
105‚Üí      if (!platformInfo.installer) continue;
106‚Üí
107‚Üí      const handler = new ConfigDrivenIdeSetup(platformCode, platformInfo);
108‚Üí      if (typeof handler.setBmadFolderName === 'function') {
109‚Üí        handler.setBmadFolderName(this.bmadFolderName);
110‚Üí      }
