115‚Üí  /**
116‚Üí   * Get all available IDEs with their metadata
117‚Üí   * @returns {Array} Array of IDE information objects
118‚Üí   */
119‚Üí  getAvailableIdes() {
120‚Üí    const ides = [];
121‚Üí
122‚Üí    for (const [key, handler] of this.handlers) {
123‚Üí      // Skip handlers without valid names
124‚Üí      const name = handler.displayName || handler.name || key;
125‚Üí
126‚Üí      // Filter out invalid entries (undefined name, empty key, etc.)
127‚Üí      if (!key || !name || typeof key !== 'string' || typeof name !== 'string') {
128‚Üí        continue;
129‚Üí      }
130‚Üí
131‚Üí      ides.push({
132‚Üí        value: key,
133‚Üí        name: name,
134‚Üí        preferred: handler.preferred || false,
135‚Üí      });
136‚Üí    }
137‚Üí
138‚Üí    // Sort: preferred first, then alphabetical
139‚Üí    ides.sort((a, b) => {
140‚Üí      if (a.preferred && !b.preferred) return -1;
141‚Üí      if (!a.preferred && b.preferred) return 1;
142‚Üí      return a.name.localeCompare(b.name);
143‚Üí    });
144‚Üí
145‚Üí    return ides;
146‚Üí  }
