171‚Üí  async setup(ideName, projectDir, bmadDir, options = {}) {
172‚Üí    const handler = this.handlers.get(ideName.toLowerCase());
173‚Üí
174‚Üí    if (!handler) {
175‚Üí      await prompts.log.warn(`IDE '${ideName}' is not yet supported`);
176‚Üí      await prompts.log.message(`Supported IDEs: ${[...this.handlers.keys()].join(', ')}`);
