197‚Üí        if (handlerResult.workflows > 0) parts.push(`${handlerResult.workflows} workflows`);
198‚Üí        if (handlerResult.tasks > 0) parts.push(`${handlerResult.tasks} tasks`);
199‚Üí        if (handlerResult.tools > 0) parts.push(`${handlerResult.tools} tools`);
200‚Üí        detail = parts.join(', ');
201‚Üí      }
202‚Üí      // Propagate handler's success status (default true for backward compat)
203‚Üí      const success = handlerResult?.success !== false;
204‚Üí      return { success, ide: ideName, detail, error: handlerResult?.error, handlerResult };
205‚Üí    } catch (error) {
