356‚Üí            const standalone = workflowData.standalone !== false && workflowData.standalone !== 'false';
357‚Üí            workflows.push({
358‚Üí              name: workflowData.name,
359‚Üí              path: fullPath,
360‚Üí              relativePath: path.relative(dir, fullPath),
361‚Üí              filename: entry.name,
362‚Üí              description: workflowData.description || '',
363‚Üí              standalone: standalone,
364‚Üí            });
365‚Üí          }
