389‚Üí    const extensions = Array.isArray(ext) ? ext : [ext];
390‚Üí
391‚Üí    const entries = await fs.readdir(dir, { withFileTypes: true });
392‚Üí
393‚Üí    for (const entry of entries) {
394‚Üí      const fullPath = path.join(dir, entry.name);
395‚Üí
396‚Üí      if (entry.isDirectory()) {
397‚Üí        // Recursively scan subdirectories
398‚Üí        const subFiles = await this.scanDirectory(fullPath, ext);
399‚Üí        files.push(...subFiles);
400‚Üí      } else if (entry.isFile()) {
401‚Üí        // Check if file matches any of the extensions
402‚Üí        const matchedExt = extensions.find((e) => entry.name.endsWith(e));
403‚Üí        if (matchedExt) {
404‚Üí          files.push({
405‚Üí            name: path.basename(entry.name, matchedExt),
406‚Üí            path: fullPath,
407‚Üí            relativePath: path.relative(dir, fullPath),
408‚Üí            filename: entry.name,
409‚Üí          });
