417‚Üí  /**
418‚Üí   * Scan a directory for files with specific extension(s) and check standalone attribute
419‚Üí   * @param {string} dir - Directory to scan
420‚Üí   * @param {string|Array<string>} ext - File extension(s) to match (e.g., '.md' or ['.md', '.xml'])
421‚Üí   * @returns {Array} List of file info objects with standalone property
422‚Üí   */
423‚Üí  async scanDirectoryWithStandalone(dir, ext) {
424‚Üí    const files = [];
425‚Üí
426‚Üí    if (!(await fs.pathExists(dir))) {
427‚Üí      return files;
428‚Üí    }
429‚Üí
430‚Üí    // Normalize ext to array
431‚Üí    const extensions = Array.isArray(ext) ? ext : [ext];
432‚Üí
433‚Üí    const entries = await fs.readdir(dir, { withFileTypes: true });
434‚Üí
435‚Üí    for (const entry of entries) {
436‚Üí      const fullPath = path.join(dir, entry.name);
437‚Üí
438‚Üí      if (entry.isDirectory()) {
439‚Üí        // Recursively scan subdirectories
440‚Üí        const subFiles = await this.scanDirectoryWithStandalone(fullPath, ext);
441‚Üí        files.push(...subFiles);
442‚Üí      } else if (entry.isFile()) {
443‚Üí        // Check if file matches any of the extensions
444‚Üí        const matchedExt = extensions.find((e) => entry.name.endsWith(e));
445‚Üí        if (matchedExt) {
446‚Üí          // Read file content to check for standalone attribute
447‚Üí          // All non-internal files are considered standalone by default
448‚Üí          let standalone = true;
449‚Üí          try {
450‚Üí            const content = await fs.readFile(fullPath, 'utf8');
451‚Üí
452‚Üí            // Skip internal/engine files (not user-facing)
453‚Üí            if (content.includes('internal="true"')) {
454‚Üí              continue;
455‚Üí            }
456‚Üí
457‚Üí            // Check for explicit standalone: false
458‚Üí            if (entry.name.endsWith('.xml')) {
459‚Üí              // For XML files, check for standalone="false" attribute
460‚Üí              const tagMatch = content.match(/<(task|tool)[^>]*standalone="false"/);
461‚Üí              standalone = !tagMatch;
462‚Üí            } else if (entry.name.endsWith('.md')) {
463‚Üí              // For MD files, parse YAML frontmatter
464‚Üí              const frontmatterMatch = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
465‚Üí              if (frontmatterMatch) {
466‚Üí                try {
467‚Üí                  const yaml = require('yaml');
468‚Üí                  const frontmatter = yaml.parse(frontmatterMatch[1]);
469‚Üí                  standalone = frontmatter.standalone !== false && frontmatter.standalone !== 'false';
470‚Üí                } catch {
471‚Üí                  // If YAML parsing fails, default to standalone
472‚Üí                }
473‚Üí              }
474‚Üí              // No frontmatter means standalone (default)
475‚Üí            }
476‚Üí          } catch {
477‚Üí            // If we can't read the file, default to standalone
478‚Üí            standalone = true;
479‚Üí          }
480‚Üí
481‚Üí          files.push({
482‚Üí            name: path.basename(entry.name, matchedExt),
483‚Üí            path: fullPath,
484‚Üí            relativePath: path.relative(dir, fullPath),
485‚Üí            filename: entry.name,
486‚Üí            standalone: standalone,
487‚Üí          });
488‚Üí        }
489‚Üí      }
490‚Üí    }
491‚Üí
492‚Üí    return files;
493‚Üí  }
