 22‚Üí * - Artifact type filtering (agents, workflows, tasks, tools)
 23‚Üí */
 24‚Üíclass ConfigDrivenIdeSetup extends BaseIdeSetup {
 25‚Üí  constructor(platformCode, platformConfig) {
 26‚Üí    super(platformCode, platformConfig.name, platformConfig.preferred);
 27‚Üí    this.platformConfig = platformConfig;
 28‚Üí    this.installerConfig = platformConfig.installer || null;
 29‚Üí
 30‚Üí    // Set configDir from target_dir so base-class detect() works
 31‚Üí    if (this.installerConfig?.target_dir) {
 32‚Üí      this.configDir = this.installerConfig.target_dir;
 33‚Üí    }
