 42‚Üí   */
 43‚Üí  async detect(projectDir) {
 44‚Üí    if (this.installerConfig?.skill_format && this.configDir) {
 45‚Üí      const dir = path.join(projectDir || process.cwd(), this.configDir);
 46‚Üí      if (await fs.pathExists(dir)) {
 47‚Üí        try {
 48‚Üí          const entries = await fs.readdir(dir);
 49‚Üí          return entries.some((e) => typeof e === 'string' && e.startsWith('bmad'));
 50‚Üí        } catch {
 51‚Üí          return false;
 52‚Üí        }
 53‚Üí      }
