 58‚Üí/**
 59‚Üí * Collect agent artifacts from the installed SKF directory.
 60‚Üí * Returns array of { name, description, relativePath }.
 61‚Üí */
 62‚Üíasync function collectAgents(skfDir, skfFolder) {
 63‚Üí  const agentsDir = path.join(skfDir, 'agents');
 64‚Üí  const agents = [];
 65‚Üí
 66‚Üí  if (!(await fs.pathExists(agentsDir))) return agents;
 67‚Üí
 68‚Üí  const files = await fs.readdir(agentsDir);
 69‚Üí  for (const file of files) {
 70‚Üí    // Look for compiled .md agent files (not .agent.yaml source)
 71‚Üí    if (!file.endsWith('.md')) continue;
 72‚Üí
 73‚Üí    const agentName = file.replace('.md', '');
 74‚Üí    const filePath = path.join(agentsDir, file);
 75‚Üí
 76‚Üí    // Try to extract description from the compiled markdown frontmatter
 77‚Üí    let description = `${agentName} agent`;
 78‚Üí    try {
 79‚Üí      const content = await fs.readFile(filePath, 'utf8');
 80‚Üí      const fmMatch = content.match(/^---\s*\n([\s\S]*?)\n---/);
 81‚Üí      if (fmMatch) {
 82‚Üí        const fm = yaml.load(fmMatch[1]);
 83‚Üí        if (fm && fm.title) description = fm.title;
 84‚Üí      }
 85‚Üí    } catch {
 86‚Üí      /* use default description */
 87‚Üí    }
 88‚Üí
 89‚Üí    agents.push({
 90‚Üí      name: agentName,
 91‚Üí      description,
 92‚Üí      relativePath: `${skfFolder}/agents/${file}`,
 93‚Üí    });
 94‚Üí  }
 95‚Üí
 96‚Üí  return agents;
 97‚Üí}
