 99‚Üí/**
100‚Üí * Collect workflow artifacts from the installed SKF directory.
101‚Üí * Returns array of { name, description, relativePath }.
102‚Üí */
103‚Üíasync function collectWorkflows(skfDir, skfFolder) {
104‚Üí  const workflowsDir = path.join(skfDir, 'workflows');
105‚Üí  const workflows = [];
106‚Üí
107‚Üí  if (!(await fs.pathExists(workflowsDir))) return workflows;
108‚Üí
109‚Üí  // Recursively find workflow.md files
110‚Üí  const walkDir = async (dir, relBase) => {
111‚Üí    const entries = await fs.readdir(dir, { withFileTypes: true });
112‚Üí    for (const entry of entries) {
113‚Üí      if (entry.isDirectory()) {
114‚Üí        await walkDir(path.join(dir, entry.name), `${relBase}/${entry.name}`);
115‚Üí      } else if (entry.name === 'workflow.md') {
116‚Üí        const filePath = path.join(dir, entry.name);
117‚Üí        const workflowName = path.basename(path.dirname(filePath));
118‚Üí
119‚Üí        // Extract description from frontmatter
120‚Üí        let description = workflowName;
121‚Üí        try {
122‚Üí          const content = await fs.readFile(filePath, 'utf8');
123‚Üí          const fmMatch = content.match(/^---\s*\n([\s\S]*?)\n---/);
124‚Üí          if (fmMatch) {
125‚Üí            const fm = yaml.load(fmMatch[1]);
126‚Üí            if (fm && fm.description) description = fm.description;
127‚Üí          }
128‚Üí        } catch {
129‚Üí          /* use default */
130‚Üí        }
131‚Üí
132‚Üí        workflows.push({
133‚Üí          name: workflowName,
134‚Üí          description,
135‚Üí          relativePath: `${skfFolder}/workflows${relBase}/workflow.md`,
136‚Üí        });
137‚Üí      }
138‚Üí    }
139‚Üí  };
140‚Üí
141‚Üí  await walkDir(workflowsDir, '');
142‚Üí  return workflows;
143‚Üí}
