145‚Üí/**
146‚Üí * Remove SKF-related command files from an IDE target directory.
147‚Üí * Only removes files matching the bmad-skf-* and bmad-agent-skf-* patterns.
148‚Üí */
149‚Üíasync function cleanSkfCommands(targetDir) {
150‚Üí  if (!(await fs.pathExists(targetDir))) return 0;
151‚Üí
152‚Üí  const files = await fs.readdir(targetDir);
153‚Üí  let removed = 0;
154‚Üí  for (const file of files) {
155‚Üí    if (file.startsWith('bmad-skf-') || file.startsWith('bmad-agent-skf-')) {
156‚Üí      await fs.remove(path.join(targetDir, file));
157‚Üí      removed++;
158‚Üí    }
159‚Üí  }
160‚Üí
161‚Üí  // Remove empty parent directories (e.g. .cursor/commands/ then .cursor/)
162‚Üí  if (removed > 0) {
163‚Üí    const remaining = await fs.readdir(targetDir);
164‚Üí    if (remaining.length === 0) {
165‚Üí      await fs.remove(targetDir);
166‚Üí      const parentDir = path.dirname(targetDir);
167‚Üí      const parentRemaining = await fs.readdir(parentDir);
168‚Üí      if (parentRemaining.length === 0) {
169‚Üí        await fs.remove(parentDir);
170‚Üí      }
171‚Üí    }
172‚Üí  }
173‚Üí
174‚Üí  return removed;
175‚Üí}
176‚Üí
177‚Üí/**
178‚Üí * Remove stale SKF command files from all known IDE directories.
179‚Üí * Called before generating new commands to handle IDE selection changes.
180‚Üí */
181‚Üíasync function cleanAllSkfCommands(projectDir) {
182‚Üí  for (const targetRelDir of Object.values(IDE_TARGETS)) {
183‚Üí    const targetDir = path.join(projectDir, targetRelDir);
184‚Üí    await cleanSkfCommands(targetDir);
185‚Üí  }
186‚Üí}
