188‚Üí/**
189‚Üí * Generate IDE command files for all selected IDEs.
190‚Üí *
191‚Üí * @param {string} projectDir - Project root directory
192‚Üí * @param {string} skfFolder - Relative path to SKF dir (e.g. '_bmad/skf')
193‚Üí * @param {string[]} ides - Array of IDE codes (e.g. ['claude-code', 'cursor'])
194‚Üí * @returns {{ generated: number, ides: string[] }}
195‚Üí */
196‚Üíasync function generateIdeCommands(projectDir, skfFolder, ides) {
197‚Üí  // Always clean old SKF commands from all IDEs first
198‚Üí  await cleanAllSkfCommands(projectDir);
199‚Üí
200‚Üí  if (!ides || ides.length === 0) return { generated: 0, ides: [] };
201‚Üí
202‚Üí  const skfDir = path.join(projectDir, skfFolder);
203‚Üí  const moduleCode = 'skf';
204‚Üí
205‚Üí  // Collect artifacts
206‚Üí  const agents = await collectAgents(skfDir, skfFolder);
207‚Üí  const workflows = await collectWorkflows(skfDir, skfFolder);
208‚Üí
209‚Üí  let totalGenerated = 0;
210‚Üí  const processedIdes = [];
211‚Üí
212‚Üí  for (const ide of ides) {
213‚Üí    const targetRelDir = IDE_TARGETS[ide];
214‚Üí    if (!targetRelDir) continue; // Skip unknown IDEs (e.g. 'other')
215‚Üí
216‚Üí    const targetDir = path.join(projectDir, targetRelDir);
217‚Üí    await fs.ensureDir(targetDir);
218‚Üí
219‚Üí    // Generate agent commands
220‚Üí    for (const agent of agents) {
221‚Üí      const fileName = `bmad-agent-${moduleCode}-${agent.name}.md`;
222‚Üí      const content = renderAgentCommand(agent.name, agent.description, agent.relativePath);
223‚Üí      await fs.writeFile(path.join(targetDir, fileName), content, 'utf8');
224‚Üí      totalGenerated++;
225‚Üí    }
226‚Üí
227‚Üí    // Generate workflow commands
228‚Üí    for (const workflow of workflows) {
229‚Üí      const fileName = `bmad-${moduleCode}-${workflow.name}.md`;
230‚Üí      const content = renderWorkflowCommand(workflow.description, workflow.relativePath);
231‚Üí      await fs.writeFile(path.join(targetDir, fileName), content, 'utf8');
232‚Üí      totalGenerated++;
233‚Üí    }
234‚Üí
235‚Üí    processedIdes.push(ide);
236‚Üí  }
237‚Üí
238‚Üí  return { generated: totalGenerated, ides: processedIdes };
239‚Üí}
240‚Üí
241‚Üímodule.exports = { generateIdeCommands };
