  }

  async copyLearningMaterial(projectDir) {
    const learnDir = path.join(projectDir, '_skf-learn');
    if (await fs.pathExists(this.docsDir)) {
      await fs.copy(this.docsDir, learnDir, {
        filter: (srcPath) => {
