  const config = await readYaml(path.join(skfDir, 'config.yaml'));

  // Read forge tier
  const forgeTier = await readYaml(path.join(sidecarDir, 'forge-tier.yaml'));

  // Read preferences
  const preferences = await readYaml(path.join(sidecarDir, 'preferences.yaml'));

  // Check agent file
  const agentFile = path.join(skfDir, 'agents', 'forger.md');
  const agentCompiled = await fs.pathExists(agentFile);

  // Count workflows
  const workflowsDir = path.join(skfDir, 'workflows', 'skillforge');
  let workflowCount = 0;
  if (await fs.pathExists(workflowsDir)) {
    const entries = await fs.readdir(workflowsDir);
    for (const entry of entries) {
      const wfPath = path.join(workflowsDir, entry, 'workflow.md');
      if (await fs.pathExists(wfPath)) {
        workflowCount++;
      }
    }
  }

  // Check output folders
  const skillsFolder = config?.skills_output_folder || 'skills';
  const forgeDataFolder = config?.forge_data_folder || 'forge-data';
  const skillsFolderExists = await fs.pathExists(path.join(projectDir, skillsFolder));
  const forgeDataFolderExists = await fs.pathExists(path.join(projectDir, forgeDataFolder));

  // Check sidecar state
  const sidecarExists = await fs.pathExists(sidecarDir);
  const tierDetected = forgeTier?.tier != null;

  // Read manifest
  const manifest = await readManifest(projectDir);

  return {
    installed: true,
    config,
    forgeTier,
    preferences,
    agentCompiled,
    workflowCount,
    skillsFolder,
    skillsFolderExists,
    forgeDataFolder,
    forgeDataFolderExists,
    sidecarExists,
    tierDetected,
    manifest,
  };
}

function displayStatus(status, version) {
  console.log('');
  console.log(chalk.cyan.bold('  Skill Forge ‚Äî Status'));
  console.log(chalk.dim(`  v${version}`));
  console.log('');

  if (!status.installed) {
    console.log(chalk.yellow('  Not installed.'));
    console.log(chalk.dim('  Run: npx skill-forge install'));
    console.log('');
    return;
  }

  const config = status.config || {};

  // Installation
  console.log(chalk.white.bold('  Installation'));
  console.log(`    Project:      ${chalk.cyan(config.project_name || '(unknown)')}`);
  console.log(`    SKF folder:   ${chalk.dim(SKF_FOLDER + '/')}`);
  console.log(`    Agent:        ${status.agentCompiled ? chalk.green('compiled') : chalk.yellow('not compiled')}`);
  console.log(`    Workflows:    ${chalk.white(status.workflowCount)}`);
  console.log('');

  // IDEs
  const ides = config.ides || [];
  console.log(chalk.white.bold('  IDEs'));
  if (ides.length > 0) {
    for (const ide of ides) {
      console.log(`    ${chalk.green('‚óè')} ${IDE_NAMES[ide] || ide}`);
    }
  } else {
    console.log(chalk.dim('    None configured'));
  }
  console.log('');

  // Forge Tier
  const ft = status.forgeTier || {};
  const tools = ft.tools || {};
  console.log(chalk.white.bold('  Forge Tier'));
  if (status.tierDetected) {
    const tierColors = { Quick: chalk.yellow, Forge: chalk.cyan, Deep: chalk.magenta };
    const tierColor = tierColors[ft.tier] || chalk.white;
    console.log(`    Tier:         ${tierColor(ft.tier)}`);
    console.log(`    Detected:     ${chalk.dim(ft.tier_detected_at || '(unknown)')}`);
  } else {
    console.log(chalk.dim('    Not detected yet ‚Äî run @Ferris SF'));
  }
  console.log(`    ast-grep:     ${formatTool(tools.ast_grep)}`);
  console.log(`    gh CLI:       ${formatTool(tools.gh_cli)}`);
  console.log(`    QMD:          ${formatTool(tools.qmd)}`);
  console.log('');

  // Output Folders
  console.log(chalk.white.bold('  Output Folders'));
  console.log(`    Skills:       ${status.skillsFolder}/ ${status.skillsFolderExists ? chalk.green('‚úì') : chalk.yellow('missing')}`);
  console.log(`    Forge data:   ${status.forgeDataFolder}/ ${status.forgeDataFolderExists ? chalk.green('‚úì') : chalk.yellow('missing')}`);
  console.log('');

  // Sidecar
  console.log(chalk.white.bold('  Sidecar'));
  console.log(`    State:        ${status.sidecarExists ? chalk.green('initialized') : chalk.yellow('missing')}`);
  console.log(`    Location:     ${chalk.dim(SIDECAR_FOLDER + '/')}`);
  console.log('');
}

function formatTool(value) {
  if (value === true || value === 'available') return chalk.green('available');
  if (value == null) return chalk.dim('not detected');
  return chalk.yellow(String(value));
}

module.exports = {
  command: 'status',
  description: 'Show SKF installation state, version, tier, and configuration',
  options: [],
  action: async () => {
    try {
      const projectDir = process.cwd();
      const packageJson = require('../../../package.json');
      const status = await getStatus(projectDir);
      displayStatus(status, packageJson.version);
    } catch (error) {
      console.error(chalk.red('\nFailed to read status:'), error.message);
      process.exit(1);
    }
  },
};

/**
 * SKF Manifest - Tracks installed files for uninstall and smart updates.
 * Writes _bmad/_config/manifest.yaml after each install.
 */

const path = require('node:path');
const fs = require('fs-extra');
const yaml = require('js-yaml');

const MANIFEST_DIR = '_bmad/_config';
const MANIFEST_FILE = 'manifest.yaml';

/**
 * Recursively collect all file paths under a directory,
 * returned as paths relative to projectDir.
 */
async function collectFiles(dir, projectDir) {
  const files = [];
  if (!(await fs.pathExists(dir))) return files;

  const entries = await fs.readdir(dir, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      const subFiles = await collectFiles(fullPath, projectDir);
      files.push(...subFiles);
    } else {
      files.push(path.relative(projectDir, fullPath));
    }
  }
  return files;
}

/**
 * Build and write the manifest after installation.
 *
 * @param {string} projectDir - Project root
 * @param {object} config - Install config (skfFolder, ides, etc.)
 * @param {object} options - Additional info (version, ideFiles)
 */
async function writeManifest(projectDir, config, options = {}) {
  const skfFolder = config.skfFolder || '_bmad/skf';
  const skfDir = path.join(projectDir, skfFolder);
  const sidecarDir = path.join(projectDir, '_bmad', '_memory', 'forger-sidecar');

  // Collect all installed files
  const skfFiles = await collectFiles(skfDir, projectDir);
  const sidecarFiles = await collectFiles(sidecarDir, projectDir);

  // Collect IDE command files
  const ideFiles = options.ideFiles || [];

  // Collect learning material files
  const learnDir = path.join(projectDir, '_skf-learn');
  const learnFiles = await collectFiles(learnDir, projectDir);

  // Collect output folder gitkeep files
  const outputFiles = [];
  for (const folder of [config.skills_output_folder || 'skills', config.forge_data_folder || 'forge-data']) {
    const gitkeep = path.join(folder, '.gitkeep');
    if (await fs.pathExists(path.join(projectDir, gitkeep))) {
      outputFiles.push(gitkeep);
    }
  }

  const manifest = {
    version: options.version || 'unknown',
    installed_at: new Date().toISOString(),
    action: config._action || 'fresh',
    module: 'skf',
    skf_folder: skfFolder,
    ides: config.ides || [],
    skills_output_folder: config.skills_output_folder || 'skills',
    forge_data_folder: config.forge_data_folder || 'forge-data',
    directories: [skfFolder, '_bmad/_memory/forger-sidecar', ...(learnFiles.length > 0 ? ['_skf-learn'] : [])],
    files: {
      skf: skfFiles,
      sidecar: sidecarFiles,
      ide_commands: ideFiles,
      learning: learnFiles,
      output: outputFiles,
    },
  };

  const manifestDir = path.join(projectDir, MANIFEST_DIR);
  await fs.ensureDir(manifestDir);

  const yamlStr = yaml.dump(manifest, { lineWidth: -1, sortKeys: false });
  await fs.writeFile(
    path.join(manifestDir, MANIFEST_FILE),
    `# SKF Installation Manifest - Generated by installer\n# Do not edit manually\n${yamlStr}`,
    'utf8',
  );
}

/**
 * Read an existing manifest, or return null if none exists.
 */
async function readManifest(projectDir) {
  const manifestPath = path.join(projectDir, MANIFEST_DIR, MANIFEST_FILE);
  try {
    const content = await fs.readFile(manifestPath, 'utf8');
    return yaml.load(content) || null;
  } catch {
    return null;
  }
}

module.exports = { writeManifest, readManifest, MANIFEST_DIR, MANIFEST_FILE };

